func (c *connection) reader() {
	for {
		_, message, err := c.ws.ReadMessage()
		if err != nil {
			break
		}
		if bytes.Contains(message, []byte(`"command":"hello"`)) {
			c.send <- []byte(`{
				"command": "hello",
				"protocols": [ "http://livereload.com/protocols/official-7" ],
				"serverName": "Hugo"
			}`)
		}
	}
	c.ws.Close()
}
